import React from 'react';
import { IconMap } from '../../../Assets/Icons';
import { useSeparator, ResponsiveElement, resolveThemeTokenForNative } from '@lmb-it/kitsconcertomobile';
import type { IIconProps } from '@lmb-it/kitsconcerto-types';

const SIZE_MAP: Record<string, number> = {
    '2xs': 12,
    'xs': 14,
    'sm': 16,
    'md': 18,
    'lg': 20,
    'xl': 24,
};

export function Icon({ name, size = 'md', color, strokeWidth, ...rest }: IIconProps) {
    const resolvedName = typeof name === 'string' && name.startsWith('pi pi-') ? name.slice(6) : name;
    const IconComponent = typeof resolvedName === 'string' ? IconMap[resolvedName] : resolvedName;
    const { cssProps, nativeProps } = useSeparator<any>(rest);

    if (!IconComponent) return null;

    const numericSize = typeof size === 'number' ? size : (SIZE_MAP[size] ?? 18);
    const resolvedColor = color ? resolveThemeTokenForNative(color) : undefined;

    return (
        <ResponsiveElement as="Box" cssProps={cssProps} nativeProps={nativeProps}>
            <IconComponent size={numericSize} color={resolvedColor} strokeWidth={strokeWidth} />
        </ResponsiveElement>
    );
}

export default Icon;
